+                .join(", ")
+        )
+    })?;
+
+    if !ctx.is_json() {
+        if dry_run {
+            println!("Dry run: checking hook installation for {}...", kind.name());
+        } else {
+            println!("Installing RCH hook for {}...", kind.name());
+        }
+    }
+
+    let result = install_hook(kind, dry_run)?;
+
+    if ctx.is_json() {
+        let _ = ctx.json(&serde_json::json!({
+            "agent": kind.id(),
+            "action": "install",
+            "result": format!("{:?}", result),
+            "dry_run": dry_run
